"""BookCollection ADT - Manages a collection of books with hidden implementation."""from typing import List, Optionalfrom ..models.book import Bookclass BookCollection:    """    Abstract Data Type for managing a collection of books.    The implementation (a dictionary keyed by ISBN) is hidden.    """    def __init__(self):        self._books = {}  # ISBN -> Book    def add_book(self, book):        """        Add a book to the collection.        Raises:            ValueError: If a book with the same ISBN already exists.        """        if book.isbn in self._books:            raise ValueError(f"Book with ISBN '{book.isbn}' already exists")        self._books[book.isbn] = book    def remove_book(self, isbn):        """        Remove a book by ISBN.        Raises:            KeyError: If book not found.            ValueError: If book is currently checked out.        """        if isbn not in self._books:            raise KeyError(f"Book with ISBN '{isbn}' not found")        book = self._books[isbn]        if not book.is_available():            raise ValueError("Cannot remove a book that is currently checked out")        del self._books[isbn]        return book    def find_by_isbn(self, isbn):        """Find a book by exact ISBN match."""        return self._books.get(isbn)    def get_all_books(self):        """Return a list of all books (defensive copy)."""        return list(self._books.values())    def get_available_books(self):        """Return a list of available books."""        return [book for book in self._books.values() if book.is_available()]    def count(self):        """Return the total number of books."""        return len(self._books)    def count_available(self):        """Return the number of available books."""        return len(self.get_available_books())